 494→    #[test]
 495→    fn empty_registry_produces_empty_graph() {
 496→        let registry = make_registry(&[]);
 497→        let graph = CallGraph::from_registry(&registry);
 498→
 499→        assert_eq!(graph.node_count(), 0);
 500→        assert_eq!(graph.edge_count(), 0);
 501→        assert!(graph.edges().is_empty());
 502→        assert!(graph.topological_layers().is_empty());
 503→        assert!(graph.cycle_groups().is_empty());
 504→    }
 505→
 506→    #[test]
 507→    fn single_node_no_edges() {
 508→        let registry = make_registry(&[("src/a.ts", "foo", vec![])]);
 509→        let graph = CallGraph::from_registry(&registry);
 510→
 511→        assert_eq!(graph.node_count(), 1);
 512→        assert_eq!(graph.edge_count(), 0);
 513→
 514→        let layers = graph.topological_layers();
 515→        assert_eq!(layers.len(), 1);
 516→        assert_eq!(layers[0], vec!["src/a.ts::foo"]);
 517→    }
 518→
 519→    #[test]
 520→    fn linear_chain_produces_correct_topo_layers() {
 521→        // A calls B, B calls C. Topo layers bottom-up: [C], [B], [A]
 522→        let registry = make_registry(&[
 523→            ("src/a.ts", "A", vec!["B"]),
 524→            ("src/a.ts", "B", vec!["C"]),
 525→            ("src/a.ts", "C", vec![]),
 526→        ]);
 527→        let graph = CallGraph::from_registry(&registry);
 528→
 529→        assert_eq!(graph.edge_count(), 2);
 530→
 531→        let layers = graph.topological_layers();
 532→        assert_eq!(layers.len(), 3);
 533→        assert_eq!(layers[0], vec!["src/a.ts::C"]);
 534→        assert_eq!(layers[1], vec!["src/a.ts::B"]);
 535→        assert_eq!(layers[2], vec!["src/a.ts::A"]);
 536→    }
 537→
 538→    #[test]
 539→    fn diamond_dependency() {
 540→        // A → B, A → C, B → D, C → D
 541→        let registry = make_registry(&[
 542→            ("src/a.ts", "A", vec!["B", "C"]),
 543→            ("src/a.ts", "B", vec!["D"]),
 544→            ("src/a.ts", "C", vec!["D"]),
 545→            ("src/a.ts", "D", vec![]),
 546→        ]);
 547→        let graph = CallGraph::from_registry(&registry);
 548→
 549→        assert_eq!(graph.edge_count(), 4);
 550→
 551→        assert_eq!(graph.callees_of("src/a.ts::A").len(), 2);
 552→        assert_eq!(graph.callers_of("src/a.ts::D").len(), 2);
 553→
 554→        let layers = graph.topological_layers();
 555→        // D first, then B and C together, then A.
 556→        assert_eq!(layers.len(), 3);
 557→        assert_eq!(layers[0], vec!["src/a.ts::D"]);
 558→        assert!(layers[1].contains(&"src/a.ts::B".to_string()));
 559→        assert!(layers[1].contains(&"src/a.ts::C".to_string()));
 560→        assert_eq!(layers[2], vec!["src/a.ts::A"]);
 561→    }
 562→
 563→    #[test]
 564→    fn cycle_detection_two_nodes() {
 565→        // A → B, B → A
 566→        let registry = make_registry(&[
 567→            ("src/a.ts", "A", vec!["B"]),
 568→            ("src/a.ts", "B", vec!["A"]),
 569→        ]);
 570→        let graph = CallGraph::from_registry(&registry);
 571→
 572→        let cycles = graph.cycle_groups();
 573→        assert_eq!(cycles.len(), 1);
 574→        assert_eq!(cycles[0].len(), 2);
 575→        assert!(cycles[0].contains(&"src/a.ts::A".to_string()));
 576→        assert!(cycles[0].contains(&"src/a.ts::B".to_string()));
 577→    }
