 597→    #[test]
 598→    fn cross_file_dependency_resolution() {
 599→        let registry = make_registry(&[
 600→            ("src/main.ts", "main", vec!["helper"]),
 601→            ("src/utils.ts", "helper", vec![]),
 602→        ]);
 603→        let graph = CallGraph::from_registry(&registry);
 604→
 605→        assert_eq!(graph.edge_count(), 1);
 606→        let edges = graph.edges();
 607→        assert_eq!(edges[0].caller, "src/main.ts::main");
 608→        assert_eq!(edges[0].callee, "src/utils.ts::helper");
 609→    }
