  1→//! Batch analyze: send Analyze requests for discovered files and aggregate into a function registry.
  2→//!
  3→//! The [`FunctionRegistry`] is a unified collection of all functions found across
  4→//! all source files. Each [`FunctionEntry`] records the file path, function metadata,
  5→//! and branch count. This registry is the input to call graph construction.
  6→
  7→use std::collections::HashMap;
  8→use std::path::{Path, PathBuf};
  9→
 10→use crate::analysis_cache::AnalysisCache;
 11→use crate::crypto_registry::CryptoRegistry;
 12→use crate::discovery::Language;
 13→use crate::frontend::{Frontend, FrontendError};
 14→use crate::protocol::{
 15→    Command as ProtoCommand, CryptoBoundary, ExternalDependency, FunctionAnalysis, ResponseResult,
 16→};
 17→use crate::types::{ParamInfo, TypeInfo};
 18→
 19→/// A single function entry in the registry.
 20→#[derive(Debug, Clone)]
 21→pub struct FunctionEntry {
 22→    /// Path to the source file containing this function.
 23→    pub file_path: PathBuf,
 24→    /// Name of the function.
 25→    pub name: String,
 26→    /// Whether the function is exported (public) from its module.
 27→    pub exported: bool,
 28→    /// Parameter types.
 29→    pub params: Vec<ParamInfo>,
 30→    /// Return type.
 31→    pub return_type: TypeInfo,
 32→    /// Dependencies (calls to other project functions or external symbols).
 33→    pub dependencies: Vec<ExternalDependency>,
 34→    /// Cryptographic API boundaries detected during analysis.
 35→    pub crypto_boundaries: Vec<CryptoBoundary>,
 36→    /// Number of branch points in the function.
 37→    pub branch_count: usize,
 38→    /// First line of the function in source.
 39→    pub start_line: u32,
 40→    /// Last line of the function in source.
 41→    pub end_line: u32,
 42→}
 43→
 44→/// Aggregated results of analyzing all discovered source files.
 45→#[derive(Debug, Clone)]
 46→pub struct FunctionRegistry {
 47→    /// All function entries, keyed by a qualified identifier (file_path::function_name).
 48→    entries: Vec<FunctionEntry>,
 49→    /// Index from qualified name to position in entries vec.
 50→    index: HashMap<String, usize>,
 51→}
 52→
 53→impl FunctionRegistry {
 54→    /// Construct a registry from pre-built entries and index.
 55→    ///
 56→    /// This is primarily useful in tests that need to build a registry without
 57→    /// going through the async `batch_analyze` pipeline.
 58→    pub fn from_raw(entries: Vec<FunctionEntry>, index: HashMap<String, usize>) -> Self {
 59→        Self { entries, index }
 60→    }
 61→
 62→    /// Number of functions in the registry.
 63→    pub fn len(&self) -> usize {
 64→        self.entries.len()
 65→    }
 66→
 67→    /// Whether the registry is empty.
 68→    pub fn is_empty(&self) -> bool {
 69→        self.entries.is_empty()
 70→    }
 71→
 72→    /// Iterate over all function entries.
 73→    pub fn entries(&self) -> &[FunctionEntry] {
 74→        &self.entries
 75→    }
 76→
 77→    /// Look up a function by its qualified name (file_path::function_name).
 78→    pub fn get(&self, qualified_name: &str) -> Option<&FunctionEntry> {
 79→        self.index.get(qualified_name).map(|&i| &self.entries[i])
 80→    }
 81→
 82→    /// Get all functions from a specific file.
 83→    pub fn functions_in_file(&self, file_path: &Path) -> Vec<&FunctionEntry> {
 84→        self.entries
 85→            .iter()
 86→            .filter(|e| e.file_path == file_path)
 87→            .collect()
 88→    }
 89→
 90→    /// Get all exported functions.
 91→    pub fn exported_functions(&self) -> Vec<&FunctionEntry> {
 92→        self.entries.iter().filter(|e| e.exported).collect()
 93→    }
 94→
 95→    /// Build a qualified name for a function in a file.
 96→    pub fn qualified_name(file_path: &Path, function_name: &str) -> String {
 97→        format!("{}::{}", file_path.display(), function_name)
 98→    }
 99→}
100→
101→/// Errors that can occur during batch analysis.
102→#[derive(Debug, thiserror::Error)]
103→pub enum BatchAnalyzeError {
104→    /// A frontend communication error.
105→    #[error("frontend error for {file}: {source}")]
106→    Frontend {
107→        file: String,
108→        source: FrontendError,
109→    },
110→    /// No frontend available for a language.
111→    #[error("no frontend configured for language: {0:?}")]
112→    NoFrontend(Language),
113→}
114→
115→/// Analyze multiple files using the appropriate frontends and build a [`FunctionRegistry`].
116→///
117→/// For each `(file_path, language)` pair, sends an Analyze request to the corresponding
118→/// frontend and aggregates results. Files are grouped by language to minimize frontend
119→/// switching overhead.
120→pub async fn batch_analyze(
121→    frontends: &mut HashMap<Language, Frontend>,
122→    files: &[(PathBuf, Language)],
123→    analysis_cache: Option<&AnalysisCache>,
124→    project_root: Option<&str>,
125→) -> Result<FunctionRegistry, BatchAnalyzeError> {
126→    let mut entries = Vec::new();
127→    let mut index = HashMap::new();
128→
129→    // Load crypto registry once for classifying dependencies across all files.
130→    let crypto_registry = match CryptoRegistry::load() {
131→        Ok(r) => Some(r),
132→        Err(e) => {
133→            log::warn!("failed to load crypto registry, skipping crypto classification: {e}");
134→            None
135→        }
136→    };
137→
138→    for (file_path, language) in files {
139→        // Check the analysis cache before calling the frontend.
140→        if let Some(cache) = analysis_cache
141→            && let Ok(Some(cached_functions)) = cache.lookup(file_path)
142→        {
143→            for func in cached_functions {
144→                let qualified = FunctionRegistry::qualified_name(file_path, &func.name);
145→                let idx = entries.len();
